"use client"

import { createContext, useContext, useEffect, useState, type ReactNode } from "react"
import { LocalDB, type User, initializeDatabase } from "./local-storage/db"
import { useRouter } from "next/navigation"

interface AuthContextType {
  user: User | null
  loading: boolean
  login: (email: string, password: string) => Promise<void>
  register: (email: string, password: string, fullName: string, role?: User["role"]) => Promise<void>
  logout: () => void
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [loading, setLoading] = useState(true)
  const router = useRouter()

  useEffect(() => {
    // Initialize database on mount
    initializeDatabase()

    // Check for existing session
    const currentUser = LocalDB.getCurrentUser()
    setUser(currentUser)
    setLoading(false)
  }, [])

  const login = async (email: string, password: string) => {
    const user = await LocalDB.loginUser(email, password)
    setUser(user)

    // Redirect based on role
    if (user.role === "admin") {
      router.push("/admin")
    } else if (user.role === "portfolio_manager") {
      router.push("/manager")
    } else {
      router.push("/dashboard")
    }
  }

  const register = async (email: string, password: string, fullName: string, role: User["role"] = "investor") => {
    const user = await LocalDB.createUser(email, password, fullName, role)
    setUser(user)
    router.push("/dashboard")
  }

  const logout = () => {
    LocalDB.logout()
    setUser(null)
    router.push("/")
  }

  return <AuthContext.Provider value={{ user, loading, login, register, logout }}>{children}</AuthContext.Provider>
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider")
  }
  return context
}
